import{_ as e,c as r,o as a,a2 as t}from"./chunks/framework.BkaCFr_r.js";const i="/assets/Hierarchy.CNvRn_ak.png",o="/assets/SWin.DsqqeQTy.png",s="/assets/structure.PML5Ivt6.png",n="/assets/windows.BtbbtKaO.png",l="/assets/visualization.BoD_BPvM.png",S=JSON.parse('{"title":"SWin Transformer","description":"","frontmatter":{},"headers":[],"relativePath":"articles/Essay_Reading/SWin_Transformer.md","filePath":"articles/Essay_Reading/SWin_Transformer.md","lastUpdated":1730396955000}'),c={name:"articles/Essay_Reading/SWin_Transformer.md"},h=t('<h1 id="swin-transformer" tabindex="-1">SWin Transformer <a class="header-anchor" href="#swin-transformer" aria-label="Permalink to &quot;SWin Transformer&quot;">вЂ‹</a></h1><p>SWin Transformer stands for Shifted Windows Transformer. This marks the first application of Transformer in the view of computer vision.</p><h2 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;Background&quot;">вЂ‹</a></h2><p>After the publication of Transformer, it is anticipated that the Transformer sturcture can be widely applied in many fields. However, <strong>large variations in the scale of visual entities</strong> and <strong>the high resolution of pixels in images</strong> are the two major challenges the field is facing.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">вЂ‹</a></h2><p>The two features of the SWin Transformer are:</p><ul><li>Hierarchical Structure <ul><li>Leverage advanced techniques for dense prediction such as feature pyramid networks (FPN) or U-Net.</li><li>Flexibility to model at various scale.</li><li>Has linear computational complexity with respect to image size. <img src="'+i+'" alt="Hierarchical Structure"></li></ul></li><li>Shifted Windows <ul><li>Bring greater efficiency by limitting self-attention computation to non-overlapping local windows while also allowing for cross-window connection. <img src="'+o+'" alt="Shifted Windows"></li></ul></li></ul><h2 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">вЂ‹</a></h2><p><img src="'+s+'" alt="Structure"></p><p>The whole structure of SWin Transformer is based on the Encoder-Decoder Transformer structure. Each of the Swin Transformer is composed of two multi-head self attention components (introduced in <a href="./Transformer.html">Transformer</a>). And the input for each is the original windows and the shifted windows.</p><p>The computation of the window partition is shown as follows. <img src="'+n+'" alt="Computation"></p><p>The mask mechanism of the above process is shown as follows. <img src="'+l+'" alt="Mask"></p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">вЂ‹</a></h2><ol><li>Ze Liu, Yutong Lin, Yue Cao, Han Hu, Yixuan Wei, Zheng Zhang, Stephen Lin, and Baining Guo. Swin Transformer: Hierarchical Vision Transformer using Shifted Windows, August 2021. arXiv:2103.14030</li><li><a href="https://www.bilibili.com/video/BV13L4y1475U/?spm_id_from=333.788&amp;vd_source=87bb079e03d49083a7a4a54e76612043" target="_blank" rel="noreferrer">Swin Transformerи®єж–‡зІѕиЇ»гЂђи®єж–‡зІѕиЇ»гЂ‘</a></li><li><a href="https://github.com/microsoft/Swin-Transformer/issues/38" target="_blank" rel="noreferrer">Issue: The Question about the mask of window attention</a></li></ol>',14),f=[h];function u(d,m,p,_,g,w){return a(),r("div",null,f)}const b=e(c,[["render",u]]);export{S as __pageData,b as default};
